import{b as o}from"./api.BhIwWj_B.js";import{authService as d}from"./auth.h-v8t-lg.js";import"./hoisted.Ds42c_VI.js";const m=document.getElementById("register-form"),t=document.getElementById("error-message"),e=document.getElementById("register-btn");m?.addEventListener("submit",async r=>{r.preventDefault(),e&&(e.classList.add("is-loading"),e.setAttribute("disabled","true")),t?.classList.add("is-hidden");const i=document.getElementById("username")?.value,n=document.getElementById("email")?.value,a=document.getElementById("password")?.value;try{const s=await o.register(i,n,a);d.setAuth(s.data),window.location.href="/"}catch(s){t&&(t.textContent=s.message||"Error al registrarse",t.classList.remove("is-hidden"))}finally{e&&(e.classList.remove("is-loading"),e.removeAttribute("disabled"))}});
